class ModelDownloader:
    """Downloads and caches pretrained model checkpoints from public repositories."""

    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.manifest_path = self.cache_dir / "manifest.json"
        self.manifest = self._load_manifest()

    def _load_manifest(self) -> Dict:
        if self.manifest_path.exists():
            with open(self.manifest_path, "r") as f:
                return json.load(f)
        return {}

    def _save_manifest(self):
        with open(self.manifest_path, "w") as f:
            json.dump(self.manifest, f, indent=2)

    def _compute_checksum(self, filepath: str) -> str:
        sha256 = hashlib.sha256()
        with open(filepath, "rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                sha256.update(chunk)
        return sha256.hexdigest()

    def download_checkpoint(self, model_name: str, force: bool = False) -> str:
        """Download a pretrained model checkpoint from a URL."""
        if model_name not in MODEL_REGISTRY:
            raise ValueError(
                f"Model '{model_name}' not found in registry. "
                f"Available models: {list(MODEL_REGISTRY.keys())}"
            )

        model_info = MODEL_REGISTRY[model_name]
        url = model_info["url"]
        filename = url.split("/")[-1]
        filepath = self.cache_dir / filename

        # Check if already cached
        if filepath.exists() and not force:
            logger.info(f"Model '{model_name}' already cached at {filepath}")
            return str(filepath)

        logger.info(f"Downloading '{model_name}' from {url}...")

        try:
            # Download with progress reporting
            def _report_progress(block_num, block_size, total_size):
                downloaded = block_num * block_size
                if total_size > 0:
                    percent = min(100, downloaded * 100 / total_size)
                    if block_num % 100 == 0:
                        logger.info(
                            f"  Download progress: {percent:.1f}% "
                            f"({downloaded / 1e6:.1f} MB / {total_size / 1e6:.1f} MB)"
                        )

            urllib.request.urlretrieve(url, str(filepath), reporthook=_report_progress)

            # Compute and store checksum
            checksum = self._compute_checksum(str(filepath))
            self.manifest[model_name] = {
                "filename": filename,
                "url": url,
                "checksum": checksum,
                "filepath": str(filepath),
            }
            self._save_manifest()

            logger.info(f"Successfully downloaded '{model_name}' to {filepath}")
            logger.info(f"  Checksum (SHA256): {checksum}")

        except Exception as e:
            if filepath.exists():
                filepath.unlink()
            raise RuntimeError(f"Failed to download model '{model_name}': {e}")

        return str(filepath)

    def load_checkpoint(self, model_name: str, device: str = "cpu") -> Dict:
        """Download (if needed) and load a checkpoint using torch.load."""
        filepath = self.download_checkpoint(model_name)

        logger.info(f"Loading checkpoint from {filepath}...")
        checkpoint = torch.load(filepath, map_location=device, weights_only=False)

        logger.info(f"Checkpoint loaded successfully. Type: {type(checkpoint)}")
        if isinstance(checkpoint, dict):
            logger.info(f"  Keys: {list(checkpoint.keys())[:10]}")

        return checkpoint

    def list_available_models(self) -> List[str]:
        return list(MODEL_REGISTRY.keys())

    def list_cached_models(self) -> List[str]:
        return list(self.manifest.keys())


