class TransferLearningPipeline:
    """Fine-tunes downloaded pretrained models on custom datasets."""

    def __init__(
        self,
        model_name: str,
        num_classes: int,
        device: Optional[str] = None,
        cache_dir: str = "./model_cache",
    ):
        self.model_name = model_name
        self.num_classes = num_classes
        self.device = device or ("cuda" if torch.cuda.is_available() else "cpu")
        self.downloader = ModelDownloader(cache_dir=cache_dir)
        self.model = None
        self.optimizer = None
        self.scheduler = None
        self.criterion = nn.CrossEntropyLoss()
        self.training_history = {"train_loss": [], "train_acc": [], "val_loss": [], "val_acc": []}

        logger.info(f"Transfer Learning Pipeline initialized")
        logger.info(f"  Model: {model_name}")
        logger.info(f"  Target classes: {num_classes}")
        logger.info(f"  Device: {self.device}")

    def _build_model(self, architecture: str) -> nn.Module:
        """Build a model architecture (without pretrained weights)."""
        architecture_map = {
            "resnet18": models.resnet18,
            "resnet50": models.resnet50,
            "vgg16": models.vgg16,
            "mobilenet_v2": models.mobilenet_v2,
            "efficientnet_b0": models.efficientnet_b0,
        }

        if architecture not in architecture_map:
            raise ValueError(f"Unknown architecture: {architecture}")

        model = architecture_map[architecture](weights=None)
        return model

    def _adapt_classifier(self, model: nn.Module, architecture: str) -> nn.Module:
        """Replace the final classification layer for the target number of classes."""
        if architecture in ["resnet18", "resnet50"]:
            num_features = model.fc.in_features
            model.fc = nn.Sequential(
                nn.Dropout(0.5),
                nn.Linear(num_features, 256),
                nn.ReLU(inplace=True),
                nn.Dropout(0.3),
                nn.Linear(256, self.num_classes),
            )
            logger.info(f"  Replaced fc layer: {num_features} -> {self.num_classes}")

        elif architecture == "vgg16":
            num_features = model.classifier[6].in_features
            model.classifier[6] = nn.Sequential(
                nn.Dropout(0.5),
                nn.Linear(num_features, 256),
                nn.ReLU(inplace=True),
                nn.Linear(256, self.num_classes),
            )
            logger.info(f"  Replaced classifier: {num_features} -> {self.num_classes}")

        elif architecture == "mobilenet_v2":
            num_features = model.classifier[1].in_features
            model.classifier = nn.Sequential(
                nn.Dropout(0.2),
                nn.Linear(num_features, self.num_classes),
            )
            logger.info(f"  Replaced classifier: {num_features} -> {self.num_classes}")

        elif architecture == "efficientnet_b0":
            num_features = model.classifier[1].in_features
            model.classifier = nn.Sequential(
                nn.Dropout(0.2),
                nn.Linear(num_features, self.num_classes),
            )
            logger.info(f"  Replaced classifier: {num_features} -> {self.num_classes}")

        return model

    def load_pretrained(
        self,
        freeze_backbone: bool = True,
        freeze_ratio: float = 0.8,
    ) -> nn.Module:
        """Download and load pretrained weights, then adapt for fine-tuning."""
        model_info = MODEL_REGISTRY[self.model_name]
        architecture = model_info["architecture"]

        # Build architecture
        logger.info(f"Building {architecture} architecture...")
        self.model = self._build_model(architecture)

        # Download and load pretrained weights
        checkpoint = self.downloader.load_checkpoint(self.model_name, device=self.device)

        # Load state dict (handle different checkpoint formats)
        if isinstance(checkpoint, dict) and "state_dict" in checkpoint:
            state_dict = checkpoint["state_dict"]
        elif isinstance(checkpoint, dict) and "model_state_dict" in checkpoint:
            state_dict = checkpoint["model_state_dict"]
        elif isinstance(checkpoint, dict):
            # Assume the dict itself is the state_dict
            state_dict = checkpoint
        else:
            raise ValueError(f"Unexpected checkpoint format: {type(checkpoint)}")

        # Clean up state dict keys (remove 'module.' prefix if present)
        cleaned_state_dict = {}
        for key, value in state_dict.items():
            new_key = key.replace("module.", "")
            cleaned_state_dict[new_key] = value

        # Load weights (allow partial loading for mismatched final layers)
        missing, unexpected = self.model.load_state_dict(
            cleaned_state_dict, strict=False
        )
        if missing:
            logger.warning(f"  Missing keys: {missing[:5]}...")
        if unexpected:
            logger.warning(f"  Unexpected keys: {unexpected[:5]}...")
        logger.info("Pretrained weights loaded successfully")

        # Adapt classifier for target number of classes
        logger.info("Adapting classifier for target task...")
        self.model = self._adapt_classifier(self.model, architecture)

        # Freeze backbone layers
        if freeze_backbone:
            self._freeze_layers(freeze_ratio)

        self.model = self.model.to(self.device)

        # Log model info
        total_params = sum(p.numel() for p in self.model.parameters())
        trainable_params = sum(
            p.numel() for p in self.model.parameters() if p.requires_grad
        )
        logger.info(f"  Total parameters: {total_params:,}")
        logger.info(f"  Trainable parameters: {trainable_params:,}")
        logger.info(
            f"  Frozen parameters: {total_params - trainable_params:,} "
            f"({(total_params - trainable_params) / total_params * 100:.1f}%)"
        )

        return self.model

    def _freeze_layers(self, freeze_ratio: float = 0.8):
        """Freeze a portion of the model's backbone layers."""
        all_params = list(self.model.named_parameters())
        num_to_freeze = int(len(all_params) * freeze_ratio)

        for i, (name, param) in enumerate(all_params):
            if i < num_to_freeze:
                param.requires_grad = False
            else:
                param.requires_grad = True

        logger.info(
            f"  Frozen {num_to_freeze}/{len(all_params)} parameter groups "
            f"({freeze_ratio * 100:.0f}%)"
        )

    def configure_optimizer(
        self,
        lr: float = 1e-3,
        backbone_lr: float = 1e-5,
        weight_decay: float = 1e-4,
        scheduler_type: str = "cosine",
        num_epochs: int = 20,
    ):
        """Configure optimizer with differential learning rates."""
        # Separate backbone and classifier parameters
        backbone_params = []
        classifier_params = []

        for name, param in self.model.named_parameters():
            if not param.requires_grad:
                continue
            if "fc" in name or "classifier" in name:
                classifier_params.append(param)
            else:
                backbone_params.append(param)

        param_groups = [
            {"params": backbone_params, "lr": backbone_lr},
            {"params": classifier_params, "lr": lr},
        ]

        self.optimizer = optim.AdamW(param_groups, weight_decay=weight_decay)

        if scheduler_type == "cosine":
            self.scheduler = optim.lr_scheduler.CosineAnnealingLR(
                self.optimizer, T_max=num_epochs
            )
        elif scheduler_type == "step":
            self.scheduler = optim.lr_scheduler.StepLR(
                self.optimizer, step_size=7, gamma=0.1
            )
        elif scheduler_type == "plateau":
            self.scheduler = optim.lr_scheduler.ReduceLROnPlateau(
                self.optimizer, mode="min", patience=3, factor=0.5
            )

        logger.info(f"Optimizer configured:")
        logger.info(f"  Backbone LR: {backbone_lr}")
        logger.info(f"  Classifier LR: {lr}")
        logger.info(f"  Weight decay: {weight_decay}")
        logger.info(f"  Scheduler: {scheduler_type}")

    def train_epoch(self, train_loader: DataLoader) -> Tuple[float, float]:
        """Train for one epoch."""
        self.model.train()
        running_loss = 0.0
        correct = 0
        total = 0

        for batch_idx, (inputs, targets) in enumerate(train_loader):
            inputs, targets = inputs.to(self.device), targets.to(self.device)

            self.optimizer.zero_grad()
            outputs = self.model(inputs)
            loss = self.criterion(outputs, targets)
            loss.backward()

            # Gradient clipping
            torch.nn.utils.clip_grad_norm_(self.model.parameters(), max_norm=1.0)

            self.optimizer.step()

            running_loss += loss.item() * inputs.size(0)
            _, predicted = outputs.max(1)
            total += targets.size(0)
            correct += predicted.eq(targets).sum().item()

            if (batch_idx + 1) % 10 == 0:
                logger.debug(
                    f"  Batch [{batch_idx + 1}/{len(train_loader)}] "
                    f"Loss: {loss.item():.4f}"
                )

        epoch_loss = running_loss / total
        epoch_acc = 100.0 * correct / total
        return epoch_loss, epoch_acc

    @torch.no_grad()
    def validate(self, val_loader: DataLoader) -> Tuple[float, float]:
        """Validate the model."""
        self.model.eval()
        running_loss = 0.0
        correct = 0
        total = 0

        for inputs, targets in val_loader:
            inputs, targets = inputs.to(self.device), targets.to(self.device)

            outputs = self.model(inputs)
            loss = self.criterion(outputs, targets)

            running_loss += loss.item() * inputs.size(0)
            _, predicted = outputs.max(1)
            total += targets.size(0)
            correct += predicted.eq(targets).sum().item()

        epoch_loss = running_loss / total
        epoch_acc = 100.0 * correct / total
        return epoch_loss, epoch_acc

    def fine_tune(
        self,
        train_loader: DataLoader,
        val_loader: DataLoader,
        num_epochs: int = 20,
        lr: float = 1e-3,
        backbone_lr: float = 1e-5,
        save_dir: str = "./fine_tuned_models",
        early_stopping_patience: int = 5,
    ) -> Dict[str, List[float]]:
        """Fine-tune the pretrained model on custom data."""
        save_path = Path(save_dir)
        save_path.mkdir(parents=True, exist_ok=True)

        # Configure optimizer
        self.configure_optimizer(
            lr=lr,
            backbone_lr=backbone_lr,
            num_epochs=num_epochs,
        )

        best_val_acc = 0.0
        patience_counter = 0
        best_model_path = None

        logger.info(f"\n{'=' * 60}")
        logger.info(f"Starting fine-tuning for {num_epochs} epochs")
        logger.info(f"{'=' * 60}")

        for epoch in range(num_epochs):
            # Train
            train_loss, train_acc = self.train_epoch(train_loader)

            # Validate
            val_loss, val_acc = self.validate(val_loader)

            # Update scheduler
            if self.scheduler:
                if isinstance(
                    self.scheduler, optim.lr_scheduler.ReduceLROnPlateau
                ):
                    self.scheduler.step(val_loss)
                else:
                    self.scheduler.step()

            # Log progress
            current_lr = self.optimizer.param_groups[-1]["lr"]
            logger.info(
                f"Epoch [{epoch + 1}/{num_epochs}] "
                f"Train Loss: {train_loss:.4f} | Train Acc: {train_acc:.2f}% | "
                f"Val Loss: {val_loss:.4f} | Val Acc: {val_acc:.2f}% | "
                f"LR: {current_lr:.2e}"
            )

            # Store history
            self.training_history["train_loss"].append(train_loss)
            self.training_history["train_acc"].append(train_acc)
            self.training_history["val_loss"].append(val_loss)
            self.training_history["val_acc"].append(val_acc)

            # Save best model
            if val_acc > best_val_acc:
                best_val_acc = val_acc
                patience_counter = 0

                best_model_path = save_path / f"{self.model_name}_best.pth"
                torch.save(
                    {
                        "epoch": epoch + 1,
                        "model_state_dict": self.model.state_dict(),
                        "optimizer_state_dict": self.optimizer.state_dict(),
                        "val_acc": val_acc,
                        "val_loss": val_loss,
                        "num_classes": self.num_classes,
                        "model_name": self.model_name,
                        "training_history": self.training_history,
                    },
                    best_model_path,
                )
                logger.info(f"  *** New best model saved (Val Acc: {val_acc:.2f}%) ***")
            else:
                patience_counter += 1

            # Early stopping
            if patience_counter >= early_stopping_patience:
                logger.info(
                    f"\nEarly stopping triggered after {epoch + 1} epochs "
                    f"(patience: {early_stopping_patience})"
                )
                break

        # Save final model
        final_model_path = save_path / f"{self.model_name}_final.pth"
        torch.save(
            {
                "epoch": epoch + 1,
                "model_state_dict": self.model.state_dict(),
                "optimizer_state_dict": self.optimizer.state_dict(),
                "num_classes": self.num_classes,
                "model_name": self.model_name,
                "training_history": self.training_history,
            },
            final_model_path,
        )

        logger.info(f"\n{'=' * 60}")
        logger.info(f"Fine-tuning complete!")
        logger.info(f"  Best validation accuracy: {best_val_acc:.2f}%")
        logger.info(f"  Best model saved at: {best_model_path}")
        logger.info(f"  Final model saved at: {final_model_path}")
        logger.info(f"{'=' * 60}")

        return self.training_history

    def load_fine_tuned(self, checkpoint_path: str) -> nn.Module:
        """Load a fine-tuned model from a checkpoint."""
        logger.info(f"Loading fine-tuned model from {checkpoint_path}...")

        checkpoint = torch.load(
            checkpoint_path, map_location=self.device, weights_only=False
        )

        if self.model is None:
            model_info = MODEL_REGISTRY[checkpoint.get("model_name", self.model_name)]
            architecture = model_info["architecture"]
            self.model = self._build_model(architecture)
            self.num_classes = checkpoint.get("num_classes", self.num_classes)
            self.model = self._adapt_classifier(self.model, architecture)

        self.model.load_state_dict(checkpoint["model_state_dict"])
        self.model = self.model.to(self.device)

        logger.info(f"  Loaded epoch: {checkpoint.get('epoch', 'N/A')}")
        logger.info(f"  Val accuracy: {checkpoint.get('val_acc', 'N/A')}")

        return self.model

    @torch.no_grad()
    def predict(self, images: torch.Tensor) -> Tuple[torch.Tensor, torch.Tensor]:
        """Run inference on a batch of images."""
        self.model.eval()
        images = images.to(self.device)
        outputs = self.model(images)
        probabilities = torch.softmax(outputs, dim=1)
        predictions = torch.argmax(probabilities, dim=1)
        return predictions, probabilities


# =====================================================================
# Unfreeze scheduler for gradual unfreezing
# =====================================================================
class GradualUnfreezer:
    """Gradually unfreezes model layers during training."""

    def __init__(self, model: nn.Module, unfreeze_schedule: Dict[int, float]):
        """
        Args:
            model: The model to unfreeze
            unfreeze_schedule: Dict mapping epoch -> freeze_ratio
                e.g., {0: 0.8, 5: 0.5, 10: 0.0} means:
                    - epoch 0-4: 80% frozen
                    - epoch 5-9: 50% frozen
                    - epoch 10+: fully unfrozen
        """
        self.model = model
        self.unfreeze_schedule = unfreeze_schedule

    def step(self, epoch: int):
        applicable_epochs = [e for e in self.unfreeze_schedule if e <= epoch]
        if not applicable_epochs:
            return

        latest_epoch = max(applicable_epochs)
        freeze_ratio = self.unfreeze_schedule[latest_epoch]

        all_params = list(self.model.named_parameters())
        num_to_freeze = int(len(all_params) * freeze_ratio)

        for i, (name, param) in enumerate(all_params):
            param.requires_grad = i >= num_to_freeze

        trainable = sum(1 for p in self.model.parameters() if p.requires_grad)
        total = sum(1 for _ in self.model.parameters())
        logger.info(
            f"  [GradualUnfreeze] Epoch {epoch}: "
            f"{trainable}/{total} trainable layers "
            f"(freeze_ratio={freeze_ratio})"
        )


# =====================================================================
# Main pipeline execution
# =====================================================================
def run_pipeline(
    model_name: str = "resnet18",
    num_classes: int = 10,
    num_epochs: int = 10,
    batch_size: int = 32,
    learning_rate: float = 1e-3,
    data_dir: Optional[str] = None,
    use_synthetic: bool = True,
    cache_dir: str = "./model_cache",
    save_dir: str = "./fine_tuned_models",
):
    """Run the complete transfer learning pipeline."""
    logger.info("=" * 60)
    logger.info("TRANSFER LEARNING PIPELINE")
    logger.info("=" * 60)

    # Step 1: Initialize pipeline
    pipeline = TransferLearningPipeline(
        model_name=model_name,
        num_classes=num_classes,
        cache_dir=cache_dir,
    )

    # Step 2: Load pretrained model
    logger.info("\n--- Step 1: Loading Pretrained Model ---")
    pipeline.load_pretrained(freeze_backbone=True, freeze_ratio=0.8)

    # Step 3: Prepare data
    logger.info("\n--- Step 2: Preparing Data ---")
    if use_synthetic or data_dir is None:
        # Create synthetic datasets for demonstration
        train_dataset = CustomImageDataset(
            num_samples=500,
            num_classes=num_classes,
            image_size=224,
        )
        val_dataset = CustomImageDataset(
            num_samples=100,
            num_classes=num_classes,
            image_size=224,
        )

        train_loader = DataLoader(
            train_dataset, batch_size=batch_size, shuffle=True, num_workers=0
        )
        val_loader = DataLoader(
            val_dataset, batch_size=batch_size, shuffle=False, num_workers=0
        )
    else:
        train_loader, val_loader, detected_classes = (
            ImageFolderDataset.create_dataloaders(
                data_dir=data_dir,
                batch_size=batch_size,
            )
        )
        logger.info(f"  Detected {detected_classes} classes from data directory")

    logger.info(f"  Train batches: {len(train_loader)}")
    logger.info(f"  Val batches: {len(val_loader)}")

    # Step 4: Fine-tune
    logger.info("\n--- Step 3: Fine-tuning ---")
    history = pipeline.fine_tune(
        train_loader=train_loader,
        val_loader=val_loader,
        num_epochs=num_epochs,
        lr=learning_rate,
        backbone_lr=learning_rate * 0.01,
        save_dir=save_dir,
        early_stopping_patience=5,
    )

    # Step 5: Test inference
    logger.info("\n--- Step 4: Testing Inference ---")
    test_images = torch.randn(4, 3, 224, 224)
    predictions, probabilities = pipeline.predict(test_images)
    logger.info(f"  Test predictions: {predictions.cpu().numpy()}")
    logger.info(
        f"  Top confidence: {probabilities.max(dim=1).values.cpu().numpy()}"
    )

    # Step 6: Load and verify saved model
    logger.info("\n--- Step 5: Verifying Saved Model ---")
    best_model_path = Path(save_dir) / f"{model_name}_best.pth"
    if best_model_path.exists():
        new_pipeline = TransferLearningPipeline(
            model_name=model_name,
            num_classes=num_classes,
            cache_dir=cache_dir,
        )
        new_pipeline.load_fine_tuned(str(best_model_path))
        new_predictions, _ = new_pipeline.predict(test_images)
        logger.info(f"  Loaded model predictions: {new_predictions.cpu().numpy()}")

    return pipeline, history


def list_models():
    """List all available pretrained models."""
    print("\nAvailable Pretrained Models:")
    print("-" * 60)
    for name, info in MODEL_REGISTRY.items():
        print(f"  {name:20s} | Architecture: {info['architecture']:15s} | "
              f"Classes: {info['num_classes']}")
    print("-" * 60)


# =====================================================================
# Entry point
# =====================================================================
if __name__ == "__main__":
    import argparse

    parser = argparse.ArgumentParser(description="Transfer Learning Pipeline")
    parser.add_argument(
        "--model",
        type=str,
        default="resnet18",
        choices=list(MODEL_REGISTRY.keys()),
        help="Pretrained model to use",
    )
    parser.add_argument(
        "--num-classes", type=int, default=10, help="Number of target classes"
    )
    parser.add_argument(
        "--epochs", type=int, default=5, help="Number of fine-tuning epochs"
    )
    parser.add_argument("--batch-size", type=int, default=32, help="Batch size")
    parser.add_argument(
        "--lr", type=float, default=1e-3, help="Learning rate"
    )
    parser.add_argument(
        "--data-dir",
        type=str,
        default=None,
        help="Path to image data directory (uses synthetic if not provided)",
    )
    parser.add_argument(
        "--cache-dir",
        type=str,
        default="./model_cache",
        help="Directory for caching downloaded models",
    )
    parser.add_argument(
        "--save-dir",
        type=str,
        default="./fine_tuned_models",
        help="Directory for saving fine-tuned models",
    )
    parser.add_argument(
        "--list-models",
        action="store_true",
        help="List available pretrained models",
    )

    args = parser.parse_args()

    if args.list_models:
        list_models()
    else:
        pipeline, history = run_pipeline(
            model_name=args.model,
            num_classes=args.num_classes,
            num_epochs=args.epochs,
            batch_size=args.batch_size,
            learning_rate=args.lr,
            data_dir=args.data_dir,
            use_synthetic=(args.data_dir is None),
            cache_dir=args.cache_dir,
            save_dir=args.save_dir,
        )

        print("\n\nTraining History Summary:")
        print("-" * 40)
        for epoch_idx in range(len(history["train_loss"])):
            print(
                f"  Epoch {epoch_idx + 1}: "
                f"Train Acc={history['train_acc'][epoch_idx]:.2f}% | "
                f"Val Acc={history['val_acc'][epoch_idx]:.2f}%"
            )